class MagixPlugins{constructor(){this.initEventListeners()}initEventListeners(){document.querySelectorAll(".btn-install-plugin").forEach((e=>{e.addEventListener("click",(t=>{t.preventDefault();const n=e.dataset.plugin;this.install(n,e)}))})),document.querySelectorAll(".btn-uninstall-plugin").forEach((e=>{e.addEventListener("click",(t=>{t.preventDefault();const n=e.dataset.plugin;this.uninstall(n,e)}))}))}async install(e,t){if(confirm(`Voulez-vous vraiment installer le plugin "${e}" ?`)){this.setLoadingState(t,!0,"Installation...");try{const n=await fetch(`index.php?controller=Plugin&action=install&name=${e}`,{method:"GET",headers:{"X-Requested-With":"XMLHttpRequest"}}),i=await n.json();i.status?i.has_config?("undefined"!=typeof MagixToast&&MagixToast.success(i.message+" Redirection vers la configuration..."),setTimeout((()=>{window.location.href=`index.php?controller=${i.plugin_name}`}),1500)):("undefined"!=typeof MagixToast&&MagixToast.success(i.message),setTimeout((()=>window.location.reload()),1500)):("undefined"!=typeof MagixToast&&MagixToast.error(i.message||"Erreur lors de l'installation."),this.setLoadingState(t,!1))}catch(e){console.error("Erreur installation plugin:",e),"undefined"!=typeof MagixToast&&MagixToast.error("Une erreur réseau inattendue est survenue."),this.setLoadingState(t,!1)}}}async uninstall(e,t){if(confirm(`ATTENTION : Désinstaller "${e}" supprimera définitivement ses données de configuration. Continuer ?`)){this.setLoadingState(t,!0);try{const n=new FormData;n.append("name",e);const i=await fetch("index.php?controller=Plugin&action=uninstall",{method:"POST",headers:{"X-Requested-With":"XMLHttpRequest"},body:n}),a=await i.json();a.status?("undefined"!=typeof MagixToast&&MagixToast.success(a.message),setTimeout((()=>window.location.reload()),1500)):("undefined"!=typeof MagixToast&&MagixToast.error(a.message),this.setLoadingState(t,!1))}catch(e){console.error("Erreur désinstallation plugin:",e),"undefined"!=typeof MagixToast&&MagixToast.error("Une erreur réseau inattendue est survenue."),this.setLoadingState(t,!1)}}}setLoadingState(e,t,n=""){e&&(t?(e.dataset.originalHtml=e.innerHTML,e.disabled=!0,e.innerHTML=`<span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span> ${n}`):(e.innerHTML=e.dataset.originalHtml||e.innerHTML,e.disabled=!1))}}document.addEventListener("DOMContentLoaded",(()=>{(document.querySelector(".btn-install-plugin")||document.querySelector(".btn-uninstall-plugin"))&&new MagixPlugins}));